// Validate required fields
const body = $input.first().json.body || $input.first().json;
const required = ['phone', 'name', 'summary', 'agentName'];

for (const field of required) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Format date/time for Argentina (UTC-3) — human readable
const now = new Date();
const handoffAt = now.toISOString();
const handoffDisplay = now.toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false
}).replace(',', ' a las') + ' hs';

return [
  {
    json: {
      phone: body.phone,
      name: body.name,
      summary: body.summary,
      agentName: body.agentName,
      language: body.language || 'es',
      handoffAt,
      handoffDisplay
    }
  }
];

